const ITEM_TYPE_SEARCH_LIMIT = 8;
const ITEM_NUMBER_GENERATION_MAX_ATTEMPTS = 25;
const LICENSOR_MERCH_GROUP_TYPE = '05';
const PROPERTY_MERCH_GROUP_TYPE = '06';

const ITEM_TYPE_SEARCH_ATTRIBUTES = [
  'item_type_id',
  'item_type_name',
  'item_type_description',
  'item_type_img_thumbnail',
  'item_type_img_fullsize'
];

const buildItemTypeSearchWhereClause = (query = '') => {
  const searchTerms = getItemTypeSearchTerms(query);
  const baseWhereClause = {
    item_type_status: 'ACTIVE'
  };

  if (!searchTerms.length) {
    return baseWhereClause;
  }

  return {
    ...baseWhereClause,
    [Op.or]: searchTerms.flatMap((term) => ([
      { item_type_name: { [Op.iLike]: `%${term}%` } },
      { item_type_description: { [Op.iLike]: `%${term}%` } }
    ]))
  };
};

const parseDivisionCodes = (value) => {
  if (value === undefined || value === null || value === '') {
    return [];
  }

  const rawValues = Array.isArray(value) ? value : String(value).split(',');
  return rawValues
    .map((item) => Number(item))
    .filter((item) => Number.isFinite(item));
};

const mapMerchGroupOption = (row) => ({
  id: row.mg_id,
  title: row.mg_desc,
  mg_code: row.mg_code,
  parent_id: row.parent_id,
  divisionCode: row.divisionCode_id_fk,
  mgCode2: row.mgCode2,
  mgCategory: row.mgCategory,
});

ItemLibrary.getLicensorsWithProperties = async (req, result) => {
  try {
    const divisionCodes = parseDivisionCodes(req.query?.divisionCode ?? req.body?.divisionCode);
    const propertyWhereClause = {
      is_active: true,
      mgTypeCode: PROPERTY_MERCH_GROUP_TYPE,
    };

    if (divisionCodes.length) {
      propertyWhereClause.divisionCode_id_fk = {
        [Op.in]: divisionCodes,
      };
    }

    const properties = await sql.merchGroup.findAll({
      attributes: ['mg_id', 'mg_code', 'mg_desc', 'divisionCode_id_fk', 'parent_id', 'mgCode2', 'mgCategory'],
      where: propertyWhereClause,
      order: [['mg_desc', 'ASC']],
      raw: true,
    });

    const licensorIds = [...new Set(
      properties
        .map((property) => property.parent_id)
        .filter((parentId) => parentId !== null && parentId !== undefined)
    )];

    if (!licensorIds.length) {
      return result(null, []);
    }

    const licensors = await sql.merchGroup.findAll({
      attributes: ['mg_id', 'mg_code', 'mg_desc', 'divisionCode_id_fk', 'parent_id', 'mgCode2', 'mgCategory'],
      where: {
        mg_id: {
          [Op.in]: licensorIds,
        },
        mgTypeCode: LICENSOR_MERCH_GROUP_TYPE,
      },
      order: [['mg_desc', 'ASC']],
      raw: true,
    });

    const propertiesByLicensorId = new Map();

    properties.forEach((property) => {
      if (property.parent_id === null || property.parent_id === undefined) {
        return;
      }

      const licensorProperties = propertiesByLicensorId.get(property.parent_id) || [];
      licensorProperties.push(mapMerchGroupOption(property));
      propertiesByLicensorId.set(property.parent_id, licensorProperties);
    });

    const licensorsWithProperties = licensors
      .map((licensor) => ({
        ...mapMerchGroupOption(licensor),
        properties: propertiesByLicensorId.get(licensor.mg_id) || [],
      }))
      .filter((licensor) => licensor.properties.length);

    result(null, licensorsWithProperties);
  } catch (err) {
    console.error('Error in getLicensorsWithProperties:', err);
    result(err, null);
  }
};

ItemLibrary.getAllitems = async (req, result) => {
  const { startRow, endRow, filterModel } = req.query;
  const limit = endRow - startRow;
  const offset = Number(startRow);
  const isArchive = req.query.isArchive === 'true';

  try {
    const filters = filterModel ? JSON.parse(filterModel) : {};

    // 🔹 Normalize multi filters
    Object.keys(filters).forEach(field => {
      if (filters[field]?.filterType === 'multi') {
        const validSubFilter = filters[field].filterModels.find(sub => sub);
        filters[field] = validSubFilter || null;
      }
    });

    const whereClause = {
