ArtPiece.getAllitems = async (req, result) => {
  const { startRow, endRow, filterModel, tags = '' } = req.query;
  const limit = endRow - startRow;
  const offset = Number(startRow);

  try {
    const filters = filterModel ? JSON.parse(filterModel) : {};

    // 🔹 Normalize multi filters
    Object.keys(filters).forEach(field => {
      if (filters[field]?.filterType === 'multi') {
        const validSubFilter = filters[field].filterModels.find(sub => sub);
        filters[field] = validSubFilter || null;
      }
    });

    // 🔹 Utility: Build Sequelize condition
    const buildCondition = (filterDef) => {
      switch (filterDef.type) {
        case 'contains': return { [Op.iLike]: `%${filterDef.filter}%` };
        case 'notContains': return { [Op.notILike]: `%${filterDef.filter}%` };
        case 'equals': return { [Op.eq]: filterDef.filter };
        case 'notEqual': return { [Op.ne]: filterDef.filter };
        case 'startsWith': return { [Op.iLike]: `${filterDef.filter}%` };
        case 'endsWith': return { [Op.iLike]: `%${filterDef.filter}` };
        default: return null;
      }
    };

    // 🔹 Base where — archive view shows inactive, main view shows active
    const isArchive = req.query.isArchive === 'true';
    const mainWhere = { is_active: isArchive ? 'false' : 'true' };

    // 🔹 Include all associations dynamically
    const associationAliases = ['licensor', 'property', 'style_guide', 'big_theme', 'little_theme', 'art_source', 'season', 'art_type', 'artist', 'age_group'];
    const include = [
      { model: sql.artPieceAttachment, as: 'artPieceAttachments', required: false },
      ...associationAliases.map(alias => {
        const mapping = mapFieldToColumn(alias);
        const model = mapping.table === 'artPiece' ? null : sql[mapping.table];
        return model ? { model, as: alias, required: false, where: {} } : null;
      }).filter(Boolean)
    ];

    // 🔹 Map filters to main table or associations
    Object.entries(filters).forEach(([field, filterDef]) => {
      if (!filterDef?.filter) return;

      const mapping = mapFieldToColumn(field); // { table, alias, column }
      // Special handling: tags filter should also search art_description
      if (mapping === 'tags' || mapping.column === 'tags') {
        const raw = typeof filterDef.filter === 'string' ? filterDef.filter : '';
        const terms = raw.split(/[\s,]+/).map(s => s.trim()).filter(Boolean);
        if (terms.length > 0) {
          mainWhere[Op.or] = mainWhere[Op.or] || [];
          terms.forEach(term => {
            mainWhere[Op.or].push({
              [Op.or]: [
                { tags: { [Op.iLike]: `%${term}%` } },
                { art_description: { [Op.iLike]: `%${term}%` } }
              ]
            });
          });
        }
        return; // handled
      }
      const condition = buildCondition(filterDef);
      if (!condition) return;

      if (mapping.table === 'artPiece') {
        mainWhere[mapping.column] = condition;
      } else {
        let assoc = include.find(i => i.as === mapping.alias);
        if (!assoc) {
          assoc = { model: sql[mapping.table], as: mapping.alias, where: {}, required: true };
          include.push(assoc);
        }
        assoc.required = true;  // inner join because we have filter
        assoc.where[mapping.column] = condition;
      }
    });

    // 🔹 Count query
    const count = await sql.artPiece.count({
      where: mainWhere,
      distinct: true,
      col: 'id',
      include
    });

    // 🔹 Paginated data query
    const rows = await sql.artPiece.findAll({
      logging: console.log,
      attributes: [
        'id', 'art_description', 'licensor_id', 'property_id',
        'style_guide_id', 'big_theme_id', 'little_theme_id',
        'art_type_id', 'art_source_id', 'artist_id',
        'season_code_id', 'age_group_id', 'divisioncode_id', 'is_active',
        'tags', 'art_number'
      ],
      where: mainWhere,
      include,
      order: [
        ['id', 'DESC'],
        [{ model: sql.artPieceAttachment, as: 'artPieceAttachments' }, 'id', 'DESC']
      ],
      limit,
      offset
    });

    const colHeaders = await getGridHeader(['artPiece']);
    const remappedData = await mapArtPiece(colHeaders, rows);

    result(null, { rows: remappedData, totalCount: count });

  } catch (err) {
    console.error('Error in ArtPiece.getAllitems:', err);
    result(null, err);
  }
};

