    'divisioncode_id': item.dataValues.divisioncode_id,
    [colHeaders.description]: item.dataValues.art_description,
    [colHeaders.pic]: item.dataValues.itemAttachments = (function () {
        let imageObj = { FullSizePicture: '', Thumbnail: '' }
        for (var i = 0; i < item.dataValues.artPieceAttachments.length; i++) {
          if (item.dataValues.artPieceAttachments[i].dataValues.display_type == 'Image' && item.dataValues.artPieceAttachments[i].dataValues.primary_image) {
            imageObj.FullSizePicture = item.dataValues.artPieceAttachments[i].dataValues.link
          } else if (item.dataValues.artPieceAttachments[i].dataValues.display_type == 'Thumb' && item.dataValues.artPieceAttachments[i].dataValues.primary_image) {
            imageObj.Thumbnail = item.dataValues.artPieceAttachments[i].dataValues.link
          }
        }
        return imageObj;
      }()),
    [colHeaders.licensor]: item.dataValues.licensor_id,
    [colHeaders.property]: item.dataValues.property_id,
    [colHeaders.style_guide]: item.dataValues.style_guide_id,
    [colHeaders.big_theme]: item.dataValues.big_theme_id,
