function buildFactoryProdOrderFilterWhere(filterModel) {
  if (!filterModel || typeof filterModel !== 'object') {
    return null;
  }
  const fieldMap = {
    'Prod Reference #': 'prodReferenceNo',
    prodReferenceNo: 'prodReferenceNo',
    'Prod Order No': 'prodOrderNo',
    prodOrderNo: 'prodOrderNo',
    Vendor: 'vendorCode',
    vendorCode: 'vendorCode'
  };
  const clauses = [];
  for (const [colId, def] of Object.entries(filterModel)) {
    if (!def) {
      continue;
    }
    let activeDef = def;
    if (activeDef.filterType === 'multi') {
      activeDef = (activeDef.filterModels || []).find((sub) => sub) || null;
    }
    if (!activeDef) {
      continue;
    }
    const isText =
      activeDef.filterType === 'text' ||
      activeDef.filterType === 'agTextColumnFilter';
    if (!isText) {
      continue;
    }
    const val = typeof activeDef.filter === 'string' ? activeDef.filter.trim() : '';
    if (!val) {
      continue;
    }
    const dbField = fieldMap[colId];
    if (dbField) {
      clauses.push({ [dbField]: { [Op.iLike]: `%${val}%` } });
    }
  }
  if (!clauses.length) {
    return null;
  }
  return clauses.length === 1 ? clauses[0] : { [Op.and]: clauses };
}

async function getVendorCodesForFactoryId(factoryId) {
  if (factoryId === undefined || factoryId === null || factoryId === '') {
    return null;
  }
  const id = Number(factoryId);
  if (Number.isNaN(id)) {
    return null;
  }

  const runJoin = async (vendorTable, extVendorTable) => {
    return sql.sequelize.query(
      `SELECT DISTINCT ev."vendorCode" AS "vendorCode"
       FROM ${extVendorTable} ev
       INNER JOIN ${vendorTable} v
         ON lower(trim(COALESCE(v."vendor_email", ''))) = lower(trim(COALESCE(ev.email, '')))
       WHERE v."factory_id_fk" = :factoryId
         AND ev."vendorCode" IS NOT NULL`,
      { replacements: { factoryId: id }, type: Sequelize.QueryTypes.SELECT }
    );
  };

  /** Same as an IN-subquery — sometimes more reliable across search_path than a raw join naming. */
  const runInSubquery = async (vendorTable, extVendorTable) => {
    return sql.sequelize.query(
      `SELECT DISTINCT ev."vendorCode" AS "vendorCode"
       FROM ${extVendorTable} ev
       WHERE ev."vendorCode" IS NOT NULL
         AND lower(trim(COALESCE(ev.email, ''))) IN (
           SELECT lower(trim(COALESCE(v2."vendor_email", '')))
           FROM ${vendorTable} v2
           WHERE v2."factory_id_fk" = :factoryId
             AND v2."vendor_email" IS NOT NULL
             AND trim(COALESCE(v2."vendor_email", '')) <> ''
         )`,
      { replacements: { factoryId: id }, type: Sequelize.QueryTypes.SELECT }
    );
  };

  const qualifiedPairs = [
    [qualifyTableName('vendor'), qualifyTableName('externalVendor')],
    ['"vendor"', '"externalVendor"']
  ];

  let rows = [];
  for (const [vt, et] of qualifiedPairs) {
    try {
      rows = await runJoin(vt, et);
      if (rows.length) {
        break;
      }
      rows = await runInSubquery(vt, et);
      if (rows.length) {
        break;
      }
    } catch (e) {
      rows = [];
    }
  }

  let codes = rows.map((r) => r.vendorCode).filter(Boolean);
  if (codes.length) {
    return codes;
  }

  for (const vt of [qualifyTableName('vendor'), '"vendor"']) {
    try {
      const emailRows = await sql.sequelize.query(
        `SELECT DISTINCT lower(trim(COALESCE("vendor_email", ''))) AS em
         FROM ${vt}
         WHERE "factory_id_fk" = :factoryId
           AND trim(COALESCE("vendor_email", '')) <> ''`,
        { replacements: { factoryId: id }, type: Sequelize.QueryTypes.SELECT }
      );
      const emails = emailRows.map((r) => r.em).filter(Boolean);
      if (!emails.length) {
        continue;
      }
      const evs = await sql.externalVendor.findAll({
        attributes: ['vendorCode'],
        where: {
          [Op.or]: emails.map((em) =>
            sql.sequelize.where(
              sql.sequelize.fn('lower', sql.sequelize.col('email')),
              em
            )
          )
        }
      });
      codes = [...new Set(evs.map((e) => e.vendorCode).filter(Boolean))];
      if (codes.length) {
        return codes;
      }
    } catch (e) {
      /* try next table qualification */
    }
  }

  return [];
}

