async function findOrCreate(data, schemaName) {
	const newItems = [];

	for (let i = 0; i < data.length; i++) {
		const record = data[i];

		if (schemaName === "merchGroup") {
			try {
				const modTime = new Date(record.modTime);
				if (isNaN(modTime)) throw new Error("Invalid modTime format");

				// Step 1: Find existing record by composite keys
				const existing = await sql[schemaName].findOne({
					where: {
						mgTypeCode: record.mgTypeCode,
						mg_desc: {
							[Op.iLike]: record.mg_desc
						},
						mg_code: record.mg_code,
						ItemNoCode: record.ItemNoCode,
						divisionCode_fk: record.divisionCode_fk,
						companyCode_fk: record.companyCode_fk,
					},
				});

				if (!existing) {
					// Step 2: Insert if not found
					const created = await sql[schemaName].create(record);
					newItems.push(created);
					console.log(`🆕 New item created: ${created.mgTypeCode} : ${created.mg_desc}`);
				} else {
					// Step 3: Update only if incoming data is newer
					const existingModTime = new Date(existing.modTime);
					if (modTime > existingModTime) {
						// Extract dynamically and filter the allowed fields whitelist (excludes mgCategory and audit fields)
						const allowedFields = Object.keys(record).filter(key =>
							!['mgCategory', 'createdTime', 'createdAt'].includes(key)
						);

						await existing.update(record, { fields: allowedFields });
						newItems.push(existing);
						console.log(`🔄 Updated merchGroup: ${existing.mgTypeCode} - ${existing.mg_desc}`);
					}
				}

				console.log(`✔ Processed item ${i + 1} of ${data.length}`);
			} catch (err) {
				console.error(`❌ Error processing record ${i + 1}: ${err.message}`);
			}
		}
	}

	return newItems;
}




