async function retryUpload(url) {

	let j = 0
	let head;
	do {
		await sleep(1000)
		head = await uploadVerification(url)
		j = j + 1;
	} while (j < 5 || parseInt(head.headers['content-length']) == 200);
	if (parseInt(head.headers['content-length']) != 200) {
		let fileName = url.split('/')
		let fileType = fileName[fileName.length - 1].split('_')[1]
		if (fileType == 'thumbnail') {
			fileType = './thumbs/'
		} else {
			fileType = './images/'
		}
		let filePath = fileType + fileName[fileName.length - 1]

		if (await fs.existsSync(filePath)) {
			await uploadToGCS(filePath, fileName[fileName.length - 1])
		} else {
			console.log("the file doesnt exist")
			return { skipped: true, url: url }
		}
		await sleep(1000)
		head = await uploadVerification(url)
		if (head.status == 200) {
			if (parseInt(head.headers['content-length']) <= 0 || parseInt(head.headers['content-length']) == 0 || parseInt(head.headers['content-length']) == -1 || parseInt(head.headers['content-length']) == null || parseInt(head.headers['content-length']) == undefined || parseInt(head.headers['content-length']) == '') {
				return { skipped: true, url: url }
			} else {
				return { skipped: false, url: url }
			}
		}
	}
}

