// Update each row by its own key, but only when the incoming record is newer
// (modTime greater than the stored value). One UPDATE per row, scoped to that row.
async function updateData(data, tableName, keyField) {
	for (let i = 0; i < data.length; i++) {
		const row = data[i];
		await sql[tableName].update(row, {
			where: {
				[keyField]: row[keyField],
				modTime: {
					[Op.lt]: row.modTime
				}
			}
		}).catch(err => {
			console.log(err)
		})
	}
}

