async function enrichLicensingStatusWithReplyStats(rows, currentUserId) {
  if (!rows?.length) return rows || [];

  const statusIds = rows.map(r => (r.get ? r.get({ plain: true }) : r).id).filter(Boolean);
  const statsMap = {};
  const userTaggedStatusIds = new Set();

  if (sql.licensingFeedbackReply && statusIds.length) {
    const replyStats = await sql.licensingFeedbackReply.findAll({
      attributes: [
        'licensing_status_id_fk',
        [Sequelize.fn('COUNT', Sequelize.col('id')), 'reply_count'],
        [Sequelize.fn('MAX', Sequelize.col('created_at')), 'latest_reply_at']
      ],
      where: { licensing_status_id_fk: { [Op.in]: statusIds } },
      group: ['licensing_status_id_fk'],
      raw: true
    });

    replyStats.forEach(s => {
      statsMap[s.licensing_status_id_fk] = s;
    });

    if (currentUserId) {
      const replies = await sql.licensingFeedbackReply.findAll({
        attributes: ['licensing_status_id_fk', 'tagged_user_ids'],
        where: { licensing_status_id_fk: { [Op.in]: statusIds } },
        raw: true
      });

      replies.forEach(r => {
        const taggedIds = Array.isArray(r.tagged_user_ids) ? r.tagged_user_ids : [];
        if (taggedIds.map(Number).includes(Number(currentUserId))) {
          userTaggedStatusIds.add(r.licensing_status_id_fk);
        }
      });
    }
  }

  return rows.map(row => {
    const plain = row.get ? row.get({ plain: true }) : { ...row };
    const stats = statsMap[plain.id] || {};
    plain.reply_count = Number(stats.reply_count) || 0;
    plain.latest_reply_at = stats.latest_reply_at || null;
    plain.has_reply_tagging_current_user = userTaggedStatusIds.has(plain.id);
    return plain;
  });
}

