    'description': { table: 'artPiece', column: 'art_description' },
    'licensor': { table: 'merchGroup', alias: 'licensor', column: 'mg_desc' },
    'property': { table: 'merchGroup', alias: 'property', column: 'mg_desc' },
    'style_guide': { table: 'merchGroup', alias: 'style_guide', column: 'mg_desc' },
