    let userInfo = await getUserInfo(req.headers.authorization);
    req.body.created_by = userInfo.user_id;
    req.body.created_at = new Date();

    // Step 1: Normalize tags to comma-separated string
    if (Array.isArray(req.body.tags)) {
      req.body.tags = req.body.tags.join(',');
    }

    // Step 2: Create the art piece in DB
    const data = await sql.artPiece.create(req.body);

    if (!data) {
      return result(null, { statusCode: 400 });
    }

    const DBres = data;

    // Step 3: Generate art_number
    const sequenceNumber = formatSequenceNumber(DBres.dataValues.id);
    const frontendHalf = req.body.art_number || ''; // e.g., "P1DYSG" from frontend
    const fullArtNumber = `${frontendHalf}-${sequenceNumber}`;

    // Update the record with the full art_number
    await DBres.update({ art_number: fullArtNumber });

    // Step 4: Handle attachments
    const attachments = [];
    if (req.body.imageLink) {
      const uuid = uuidv4();
      attachments.push(
        {
          uuid,
          type: `image/${req.body.imageLink.split(".").pop().toLowerCase()}`,
