          display_type: "Thumb",
          company_code: req.body.company_code,
          link: req.body.thumbImageLink,
          art_piece_id: DBres.dataValues.id,
          created_at: new Date(),
          created_by: userInfo.user_id,
          updated_at: null,
          updated_by: null,
          file_name: req.body.thumbImageLink.split("/").pop(),
          divisioncode_id: req.body.selectedDivisionCode.divCode_id
        }
      );
    }

    // Step 5: Save attachments
    for (const attachment of attachments) {
      const [item, created] = await sql.artPieceAttachment.findOrCreate({
        where: {
          art_piece_id: DBres.dataValues.id,
          file_name: attachment.file_name
        },
        defaults: attachment
      });
    }

    // Step 6: Return success with art_number
    result(null, { statusCode: 200, art_number: fullArtNumber });

  } catch (err) {
    result(null, err);
  }
};


