describe('ProdTracking.getViewlayout (missing-Default-layout guard)', () => {
  beforeEach(() => jest.clearAllMocks());

  it('returns the layout for access rows that have a matching Default layout', async () => {
    sql.GridAccessLevel.findAll.mockResolvedValue([accessRow([layout('Default')])]);

    const { err, data } = await run(ProdTracking.getViewlayout, req);

    expect(err).toBeFalsy();
    expect(data).toEqual([{ layout_name: 'Default' }]);
  });

  it('skips access rows with NO matching layout instead of crashing the request', async () => {
    // The bug: dereferencing GridLayouts[0] on an empty array threw and hung the request.
    sql.GridAccessLevel.findAll.mockResolvedValue([
      accessRow([]),                 // no Default layout -> must be skipped, not crash
      accessRow([layout('Default')]) // valid -> still returned
    ]);

    const { err, data } = await run(ProdTracking.getViewlayout, req);

    expect(err).toBeFalsy();
    expect(data).toEqual([{ layout_name: 'Default' }]);
  });

  it('returns an empty list (no error) when no row has a layout', async () => {
    sql.GridAccessLevel.findAll.mockResolvedValue([accessRow([]), accessRow(null)]);

    const { err, data } = await run(ProdTracking.getViewlayout, req);

    expect(err).toBeFalsy();
    expect(data).toEqual([]);
  });

