jest.mock('../../models/db', () => ({
  externalVendor: { bulkCreate: jest.fn().mockResolvedValue(undefined), update: jest.fn().mockResolvedValue([1]) },
  externalCustomer: { bulkCreate: jest.fn().mockResolvedValue(undefined), update: jest.fn().mockResolvedValue([1]) },
}));

const { Op } = require('sequelize');
const axios = require('axios');
const sql = require('../../models/db');
const Customer = require('../../models/lib.model');

// getData resolves to response.data, so axios must resolve to { data: <payload> }.
const mockColdLion = (payload) => axios.mockResolvedValue({ data: payload });

afterEach(() => jest.clearAllMocks());

describe('Customer.getExternalVendor (regression: undefined `i` ReferenceError)', () => {
  test('does NOT throw and reports success for a non-empty payload', async () => {
    mockColdLion({ content: [
      { vendorCode: 'V1', modTime: '2024-01-01' },
      { vendorCode: 'V2', modTime: '2024-02-02' },
    ] });

    const result = jest.fn();
    // Before the fix this threw "ReferenceError: i is not defined".
    await expect(Customer.getExternalVendor({}, result)).resolves.toBeUndefined();

    expect(result).toHaveBeenCalledTimes(1);
    expect(result.mock.calls[0][0]).toBeNull(); // no error
  });

  test('bulk-inserts the payload (ignoreDuplicates) once', async () => {
    const content = [{ vendorCode: 'V1', modTime: '2024-01-01' }];
    mockColdLion({ content });

    await Customer.getExternalVendor({}, jest.fn());

    expect(sql.externalVendor.bulkCreate).toHaveBeenCalledTimes(1);
    const [rows, opts] = sql.externalVendor.bulkCreate.mock.calls[0];
    expect(rows).toEqual(content);
    expect(opts.ignoreDuplicates).toBe(true);
  });

  test('updates each row scoped to its OWN key + newer-modTime guard (not a shared condition)', async () => {
    mockColdLion({ content: [
      { vendorCode: 'V1', modTime: '2024-01-01' },
      { vendorCode: 'V2', modTime: '2024-02-02' },
    ] });

    await Customer.getExternalVendor({}, jest.fn());

    expect(sql.externalVendor.update).toHaveBeenCalledTimes(2);
    const firstWhere = sql.externalVendor.update.mock.calls[0][1].where;
    const secondWhere = sql.externalVendor.update.mock.calls[1][1].where;
    expect(firstWhere.vendorCode).toBe('V1');
    expect(firstWhere.modTime[Op.lt]).toBe('2024-01-01');
    expect(secondWhere.vendorCode).toBe('V2'); // per-row, not V1 reused
    expect(secondWhere.modTime[Op.lt]).toBe('2024-02-02');
  });

  test('reports "No data was found" and writes nothing for an empty payload', async () => {
    mockColdLion({ content: [] });

    const result = jest.fn();
    await Customer.getExternalVendor({}, result);

    expect(sql.externalVendor.bulkCreate).not.toHaveBeenCalled();
    expect(sql.externalVendor.update).not.toHaveBeenCalled();
    expect(result).toHaveBeenCalledWith(null, 'No data was found');
  });

  test('does not crash the process when the upstream fetch fails', async () => {
    // getData swallows the axios error and returns undefined → data.content throws,
    // which the try/catch must absorb and report rather than crash.
    axios.mockResolvedValue(undefined);

    const result = jest.fn();
    await expect(Customer.getExternalVendor({}, result)).resolves.toBeUndefined();
    expect(result).toHaveBeenCalledTimes(1);
  });
});

describe('Customer.getExternalCustomer (regression: undefined `i` ReferenceError)', () => {
  test('does NOT throw and updates each row by its own customerCode', async () => {
    mockColdLion({ content: [
      { customerCode: 'C1', modTime: '2024-03-03' },
      { customerCode: 'C2', modTime: '2024-04-04' },
    ] });

    const result = jest.fn();
    await expect(Customer.getExternalCustomer({}, result)).resolves.toBeUndefined();

    expect(sql.externalCustomer.bulkCreate).toHaveBeenCalledTimes(1);
    expect(sql.externalCustomer.update).toHaveBeenCalledTimes(2);
    const firstWhere = sql.externalCustomer.update.mock.calls[0][1].where;
    expect(firstWhere.customerCode).toBe('C1');
    expect(firstWhere.modTime[Op.lt]).toBe('2024-03-03');
    expect(result.mock.calls[0][0]).toBeNull();
  });

  test('reports "No data was found" for an empty payload', async () => {
    mockColdLion({ content: [] });
    const result = jest.fn();
    await Customer.getExternalCustomer({}, result);
    expect(result).toHaveBeenCalledWith(null, 'No data was found');
  });
});

