const crypto = require("crypto");
const {
  apiKeyAuthMiddleware,
  findApiKeyEntry,
  hashApiKey,
  parseApiKeys,
  signInternalJwt,
} = require("../../src/apiKeyAuth");

function decodeJwtPayload(token) {
  const payload = token.split(".")[1];
  const padded = payload + "=".repeat((4 - (payload.length % 4)) % 4);
  return JSON.parse(Buffer.from(padded.replace(/-/g, "+").replace(/_/g, "/"), "base64").toString("utf8"));
}

describe("apiKeyAuth", () => {
  const previousEnv = process.env;
  let keyPair;

  beforeEach(() => {
    jest.resetModules();
    process.env = { ...previousEnv };
    keyPair = crypto.generateKeyPairSync("rsa", { modulusLength: 2048 });
    process.env.JWT_PRIVATE_KEY = keyPair.privateKey.export({ type: "pkcs8", format: "pem" });
    process.env.API_KEY_JWT_TTL = "1h";
  });

  afterEach(() => {
    process.env = previousEnv;
  });

  test("parses hashed API keys and finds matching entries", () => {
    process.env.DESIGNFLOW_API_KEYS = JSON.stringify([
      {
        name: "external-client",
        keyHash: hashApiKey("df_live_test"),
        claims: {
          name: "API User",
          user_id: 34,
          email: "api-user@example.com",
          role: "admin",
        },
      },
    ]);

    const entries = parseApiKeys();
    expect(entries).toHaveLength(1);
    expect(findApiKeyEntry("df_live_test", entries).name).toBe("external-client");
    expect(findApiKeyEntry("wrong", entries)).toBeUndefined();
  });

  test("signs an internal Designflow JWT with API key claims", () => {
    const token = signInternalJwt({
      name: "API User",
      user_id: 34,
      email: "api-user@example.com",
      role: "admin",
      api_key_name: "external-client",
    });

    const payload = decodeJwtPayload(token);
    expect(payload).toEqual(expect.objectContaining({
      user_id: 34,
      email: "api-user@example.com",
      role: "admin",
      auth_type: "api_key",
      api_key_name: "external-client",
    }));
    expect(payload.exp - payload.iat).toBe(3600);
  });

  test("middleware replaces X-API-Key with an Authorization JWT", () => {
    process.env.DESIGNFLOW_API_KEYS = JSON.stringify([
      {
        name: "external-client",
        keyHash: hashApiKey("df_live_test"),
        claims: {
          name: "API User",
          user_id: 34,
          email: "api-user@example.com",
          role: "admin",
        },
      },
    ]);

    const req = { headers: { "x-api-key": "df_live_test" } };
    const res = {
      status: jest.fn().mockReturnThis(),
      json: jest.fn(),
    };
    const next = jest.fn();

    apiKeyAuthMiddleware(req, res, next);

    expect(next).toHaveBeenCalled();
    expect(req.headers["x-api-key"]).toBeUndefined();
    expect(req.headers.authorization).toMatch(/^ey/);
    expect(decodeJwtPayload(req.headers.authorization).role).toBe("admin");
  });

  test("middleware rejects invalid API keys", () => {
    process.env.DESIGNFLOW_API_KEYS = JSON.stringify([
      {
        name: "external-client",
        keyHash: hashApiKey("df_live_test"),
        claims: {
          name: "API User",
          user_id: 34,
          email: "api-user@example.com",
          role: "admin",
        },
      },
    ]);

    const req = { headers: { "x-api-key": "wrong" } };
    const res = {
      status: jest.fn().mockReturnThis(),
      json: jest.fn(),
    };
    const next = jest.fn();

    apiKeyAuthMiddleware(req, res, next);

    expect(next).not.toHaveBeenCalled();
    expect(res.status).toHaveBeenCalledWith(401);
    expect(res.json).toHaveBeenCalledWith({ error: "Invalid API key" });
  });
});

